'use client';

import { useEffect, useState, useRef } from 'react';
import { Send, Search, MessageCircle, Check, CheckCheck, Clock, XCircle, ArrowLeft } from 'lucide-react';
import api from '@/lib/api';

interface Contact {
  wa_id: string;
  name: string;
  last_message: string;
  last_message_time: string | null;
  direction: string | null;
}

interface Message {
  id: number;
  wa_message_id: string;
  direction: string;
  type: string;
  content: string;
  timestamp: string;
  status: string;
}

export default function ConversationsPage() {
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [selectedContact, setSelectedContact] = useState<Contact | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const [mounted, setMounted] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => { setMounted(true); }, []);

  useEffect(() => {
    loadContacts();
    const interval = setInterval(loadContacts, 5000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (selectedContact) {
      loadMessages(selectedContact.wa_id);
      const interval = setInterval(() => loadMessages(selectedContact.wa_id), 3000);
      return () => clearInterval(interval);
    }
  }, [selectedContact]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const loadContacts = async () => {
    try {
      const res = await api.get('/contacts');
      setContacts(res.data);
    } catch (err) {
      console.error('Erro ao carregar contatos:', err);
    } finally {
      setLoading(false);
    }
  };

  const loadMessages = async (waId: string) => {
    try {
      const res = await api.get(`/contacts/${waId}/messages`);
      setMessages(res.data);
    } catch (err) {
      console.error('Erro ao carregar mensagens:', err);
    }
  };

  const handleSend = async () => {
    if (!newMessage.trim() || !selectedContact || sending) return;
    setSending(true);
    try {
      await api.post('/send/text', { to: selectedContact.wa_id, text: newMessage });
      setNewMessage('');
      await loadMessages(selectedContact.wa_id);
      await loadContacts();
    } catch (err) {
      console.error('Erro ao enviar:', err);
    } finally {
      setSending(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const getInitials = (name: string) =>
    name.split(' ').map((n) => n[0]).join('').toUpperCase().slice(0, 2);

  const getAvatarColor = (name: string) => {
    const colors = [
      'from-blue-500 to-blue-600',
      'from-purple-500 to-purple-600',
      'from-green-500 to-green-600',
      'from-orange-500 to-orange-600',
      'from-pink-500 to-pink-600',
      'from-cyan-500 to-cyan-600',
      'from-indigo-500 to-indigo-600',
    ];
    return colors[name.charCodeAt(0) % colors.length];
  };

  const formatTime = (timestamp: string) => {
    const date = new Date(timestamp);
    return date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
  };

  const formatDate = (timestamp: string) => {
    const date = new Date(timestamp);
    const today = new Date();
    if (date.toDateString() === today.toDateString()) return 'Hoje';
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);
    if (date.toDateString() === yesterday.toDateString()) return 'Ontem';
    return date.toLocaleDateString('pt-BR');
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'sent': return <Check className="w-3.5 h-3.5 text-gray-400" />;
      case 'delivered': return <CheckCheck className="w-3.5 h-3.5 text-gray-400" />;
      case 'read': return <CheckCheck className="w-3.5 h-3.5 text-blue-500" />;
      default: return <Clock className="w-3.5 h-3.5 text-gray-400" />;
    }
  };

  const filteredContacts = contacts.filter(c =>
    c.name.toLowerCase().includes(search.toLowerCase()) ||
    c.wa_id.includes(search)
  );

  // Agrupar mensagens por data
  const groupedMessages: { date: string; msgs: Message[] }[] = [];
  messages.forEach((msg) => {
    const date = formatDate(msg.timestamp);
    const lastGroup = groupedMessages[groupedMessages.length - 1];
    if (lastGroup && lastGroup.date === date) {
      lastGroup.msgs.push(msg);
    } else {
      groupedMessages.push({ date, msgs: [msg] });
    }
  });

  return (
    <div className="h-screen flex bg-gray-50">
      {/* Sidebar Contatos */}
      <div className={`${selectedContact ? 'hidden md:flex' : 'flex'} w-full md:w-[380px] flex-col border-r border-gray-200 bg-white`}>
        {/* Header */}
        <div className="px-5 py-4 border-b border-gray-100">
          <div className={`transition-all duration-700 ease-out ${mounted ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4'}`}>
            <p className="text-sm font-medium text-[#2A658F] mb-1">WhatsApp</p>
            <h1 className="text-2xl font-semibold text-[#27273D] tracking-tight">Conversas</h1>
          </div>
          <div className="relative mt-4">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              placeholder="Buscar contato..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-11 pr-4 py-2.5 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:border-[#2A658F] focus:ring-4 focus:ring-[#2A658F]/10 transition-all duration-200 outline-none"
            />
            {search && (
              <button onClick={() => setSearch('')} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600">
                <XCircle className="w-4 h-4" />
              </button>
            )}
          </div>
        </div>

        {/* Lista de contatos */}
        <div className="flex-1 overflow-y-auto">
          {loading ? (
            <div className="animate-pulse space-y-1 p-3">
              {[...Array(5)].map((_, i) => (
                <div key={i} className="flex items-center gap-3 p-3">
                  <div className="w-12 h-12 bg-gray-100 rounded-full" />
                  <div className="flex-1 space-y-2">
                    <div className="h-4 bg-gray-100 rounded w-32" />
                    <div className="h-3 bg-gray-100 rounded w-48" />
                  </div>
                </div>
              ))}
            </div>
          ) : filteredContacts.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-gray-400">
              <MessageCircle className="w-12 h-12 mb-3" />
              <p className="text-sm">Nenhuma conversa encontrada</p>
            </div>
          ) : (
            filteredContacts.map((contact) => (
              <button
                key={contact.wa_id}
                onClick={() => setSelectedContact(contact)}
                className={`w-full flex items-center gap-3 px-5 py-3.5 hover:bg-gray-50 transition-colors text-left ${
                  selectedContact?.wa_id === contact.wa_id ? 'bg-[#2A658F]/5 border-r-2 border-[#2A658F]' : ''
                }`}
              >
                <div className={`w-12 h-12 rounded-full bg-gradient-to-br ${getAvatarColor(contact.name)} flex items-center justify-center text-white font-semibold text-sm shadow-sm flex-shrink-0`}>
                  {getInitials(contact.name || contact.wa_id)}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center justify-between">
                    <p className="font-semibold text-sm text-[#27273D] truncate">{contact.name || contact.wa_id}</p>
                    {contact.last_message_time && (
                      <span className="text-xs text-gray-400 ml-2 flex-shrink-0">{formatTime(contact.last_message_time)}</span>
                    )}
                  </div>
                  <p className="text-xs text-gray-500 truncate mt-0.5">
                    {contact.direction === 'outbound' && '✓ '}
                    {contact.last_message || 'Sem mensagens'}
                  </p>
                </div>
              </button>
            ))
          )}
        </div>
      </div>

      {/* Área de Chat */}
      <div className={`${selectedContact ? 'flex' : 'hidden md:flex'} flex-1 flex-col`}>
        {selectedContact ? (
          <>
            {/* Header do chat */}
            <div className="px-5 py-3.5 border-b border-gray-200 bg-white flex items-center gap-3">
              <button onClick={() => setSelectedContact(null)} className="md:hidden p-1 hover:bg-gray-100 rounded-lg">
                <ArrowLeft className="w-5 h-5 text-gray-600" />
              </button>
              <div className={`w-10 h-10 rounded-full bg-gradient-to-br ${getAvatarColor(selectedContact.name)} flex items-center justify-center text-white font-semibold text-xs shadow-sm`}>
                {getInitials(selectedContact.name || selectedContact.wa_id)}
              </div>
              <div>
                <p className="font-semibold text-sm text-[#27273D]">{selectedContact.name || selectedContact.wa_id}</p>
                <p className="text-xs text-gray-500">+{selectedContact.wa_id}</p>
              </div>
            </div>

            {/* Mensagens */}
            <div className="flex-1 overflow-y-auto px-5 py-4 space-y-1" style={{ backgroundImage: 'url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%239C92AC\' fill-opacity=\'0.03\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")' }}>
              {groupedMessages.map((group) => (
                <div key={group.date}>
                  <div className="flex justify-center my-3">
                    <span className="px-3 py-1 bg-white rounded-lg text-xs text-gray-500 shadow-sm">{group.date}</span>
                  </div>
                  {group.msgs.map((msg) => (
                    <div key={msg.id} className={`flex mb-1.5 ${msg.direction === 'outbound' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[75%] px-3.5 py-2 rounded-2xl shadow-sm ${
                        msg.direction === 'outbound'
                          ? 'bg-[#2A658F] text-white rounded-br-md'
                          : 'bg-white text-gray-800 rounded-bl-md'
                      }`}>
                        <p className="text-sm whitespace-pre-wrap break-words">{msg.content}</p>
                        <div className={`flex items-center justify-end gap-1 mt-1 ${msg.direction === 'outbound' ? 'text-white/70' : 'text-gray-400'}`}>
                          <span className="text-[10px]">{formatTime(msg.timestamp)}</span>
                          {msg.direction === 'outbound' && getStatusIcon(msg.status)}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              ))}
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div className="px-5 py-3.5 border-t border-gray-200 bg-white">
              <div className="flex items-end gap-3">
                <textarea
                  value={newMessage}
                  onChange={(e) => setNewMessage(e.target.value)}
                  onKeyDown={handleKeyPress}
                  placeholder="Digite uma mensagem..."
                  rows={1}
                  className="flex-1 px-4 py-2.5 bg-gray-50 border border-gray-200 rounded-xl text-sm text-gray-800 resize-none focus:border-[#2A658F] focus:ring-4 focus:ring-[#2A658F]/10 transition-all duration-200 outline-none"
                />
                <button
                  onClick={handleSend}
                  disabled={!newMessage.trim() || sending}
                  className="flex items-center justify-center w-10 h-10 bg-gradient-to-r from-[#2A658F] to-[#3d7ba8] rounded-xl text-white hover:shadow-lg hover:shadow-[#2A658F]/30 hover:-translate-y-0.5 transition-all duration-200 disabled:opacity-50 disabled:hover:translate-y-0 disabled:hover:shadow-none flex-shrink-0"
                >
                  <Send className="w-4 h-4" />
                </button>
              </div>
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-gray-400">
            <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mb-4">
              <MessageCircle className="w-10 h-10" />
            </div>
            <p className="text-lg font-medium text-[#27273D]">Cenat WhatsApp</p>
            <p className="text-sm mt-1">Selecione uma conversa para começar</p>
          </div>
        )}
      </div>
    </div>
  );
}
